# Script to generate 300 new JSON sample files with genuine variety
import json
import os
import random

base_dir = r"C:\Users\CartridgeStack\Qwen-Tokenizer-Pruner\sample_data"
os.makedirs(base_dir, exist_ok=True)

def write_json(idx, query, response):
    path = os.path.join(base_dir, f"{idx}.json")
    data = {"query": query, "response": response}
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

