    ("Implement a priority queue in Python using heapq with updateable priorities.", "import heapq\n\nclass UpdatablePriorityQueue:\n    def __init__(self):\n        self._queue = []\n        self._entry_finder = {}\n        self._counter = 0\n\n    def add_task(self, task, priority=0):\n        if task in self._entry_finder:\n            self.remove_task(task)\n        entry = [priority, self._counter, task]\n        self._counter += 1\n        self._entry_finder[task] = entry\n        heapq.heappush(self._queue, entry)\n\n    def remove_task(self, task):\n        entry = self._entry_finder.pop(task)\n        entry[-1] = None\n\n    def pop_task(self):\n        while self._queue:\n            priority, count, task = heapq.heappop(self._queue)\n            if task is not None:\n                del self._entry_finder[task]\n                return task\n        raise KeyError('pop from an empty queue')"),
