    ("Build a WebSocket chat server in Node.js using the ws library with room support.", "const WebSocket = require('ws');\nconst wss = new WebSocket.Server({ port: 8080 });\nconst rooms = new Map();\n\nwss.on('connection', (ws) => {\n    let currentRoom = null;\n    ws.on('message', (data) => {\n        const { type, room, message } = JSON.parse(data);\n        if (type === 'join') {\n            currentRoom = room;\n            if (!rooms.has(room)) rooms.set(room, new Set());\n            rooms.get(room).add(ws);\n        } else if (type === 'chat' && currentRoom) {\n            rooms.get(currentRoom).forEach(client => {\n                if (client.readyState === WebSocket.OPEN) {\n                    client.send(JSON.stringify({ room: currentRoom, message }));\n                }\n            });\n        }\n    });\n});"),
    ("Implement a JavaScript event emitter from scratch that supports once listeners.", "class EventEmitter {\n    constructor() {\n        this.events = {};\n    }\n    on(event, listener) {\n        if (!this.events[event]) this.events[event] = [];\n        this.events[event].push(listener);\n    }\n    once(event, listener) {\n        const onceWrapper = (...args) => {\n            listener(...args);\n            this.off(event, onceWrapper);\n        };\n        this.on(event, onceWrapper);\n    }\n    off(event, listener) {\n        if (!this.events[event]) return;\n        this.events[event] = this.events[event].filter(l => l !== listener);\n    }\n    emit(event, ...args) {\n        if (!this.events[event]) return;\n        this.events[event].forEach(l => l(...args));\n    }\n}"),
