    ("Write a Go program that implements a worker pool pattern with bounded concurrency.", "package main\n\nimport (\n    \"fmt\"\n    \"sync\"\n)\n\nfunc worker(id int, jobs <-chan int, results chan<- int, wg *sync.WaitGroup) {\n    defer wg.Done()\n    for j := range jobs {\n        results <- j * 2\n    }\n}\n\nfunc main() {\n    jobs := make(chan int, 100)\n    results := make(chan int, 100)\n    var wg sync.WaitGroup\n\n    for w := 1; w <= 3; w++ {\n        wg.Add(1)\n        go worker(w, jobs, results, &wg)\n    }\n\n    for j := 1; j <= 9; j++ {\n        jobs <- j\n    }\n    close(jobs)\n    wg.Wait()\n    close(results)\n\n    for r := range results {\n        fmt.Println(r)\n    }\n}"),
