    ("Write a C program that implements a custom memory allocator using a free list.", "#include <stdlib.h>\n#include <string.h>\n\ntypedef struct Block {\n    size_t size;\n    struct Block *next;\n} Block;\n\nstatic Block *free_list = NULL;\n\nvoid *my_alloc(size_t size) {\n    Block **curr = &free_list;\n    while (*curr) {\n        if ((*curr)->size >= size) {\n            Block *found = *curr;\n            *curr = found->next;\n            return (char*)found + sizeof(Block);\n        }\n        curr = &(*curr)->next;\n    }\n    Block *block = malloc(sizeof(Block) + size);\n    block->size = size;\n    return (char*)block + sizeof(Block);\n}\n\nvoid my_free(void *ptr) {\n    Block *block = (Block*)((char*)ptr - sizeof(Block));\n    block->next = free_list;\n    free_list = block;\n}"),
