    # Algorithms / Data Structures
    ("Implement Dijkstra's shortest path algorithm in Python with a priority queue.", "import heapq\n\ndef dijkstra(graph, start):\n    dist = {node: float('inf') for node in graph}\n    dist[start] = 0\n    pq = [(0, start)]\n\n    while pq:\n        d, node = heapq.heappop(pq)\n        if d > dist[node]:\n            continue\n        for neighbor, weight in graph[node]:\n            new_dist = dist[node] + weight\n            if new_dist < dist[neighbor]:\n                dist[neighbor] = new_dist\n                heapq.heappush(pq, (new_dist, neighbor))\n    return dist\n\n# Example graph:\n# graph = {\n#     'A': [('B', 1), ('C', 4)],\n#     'B': [('C', 2), ('D', 5)],\n#     'C': [('D', 1)],\n#     'D': []\n# }"),
    ("Write a Python implementation of the Trie (prefix tree) data structure.", "class TrieNode:\n    def __init__(self):\n        self.children = {}\n        self.is_end = False\n\nclass Trie:\n    def __init__(self):\n        self.root = TrieNode()\n\n    def insert(self, word):\n        node = self.root\n        for char in word:\n            if char not in node.children:\n                node.children[char] = TrieNode()\n            node = node.children[char]\n        node.is_end = True\n\n    def search(self, word):\n        node = self._find_node(word)\n        return node is not None and node.is_end\n\n    def starts_with(self, prefix):\n        return self._find_node(prefix) is not None\n\n    def _find_node(self, prefix):\n        node = self.root\n        for char in prefix:\n            if char not in node.children:\n                return None\n            node = node.children[char]\n        return node"),
    ("Implement the A* pathfinding algorithm in Python for a 2D grid.", "import heapq\n\ndef heuristic(a, b):\n    return abs(a[0] - b[0]) + abs(a[1] - b[1])\n\ndef astar(grid, start, goal):\n    rows, cols = len(grid), len(grid[0])\n    open_set = [(0, start)]\n    came_from = {}\n    g_score = {start: 0}\n    f_score = {start: heuristic(start, goal)}\n\n    while open_set:\n        _, current = heapq.heappop(open_set)\n        if current == goal:\n            path = []\n            while current in came_from:\n                path.append(current)\n                current = came_from[current]\n            return path[::-1]\n\n        for dy, dx in [(-1,0),(1,0),(0,-1),(0,1)]:\n            neighbor = (current[0]+dy, current[1]+dx)\n            if 0 <= neighbor[0] < rows and 0 <= neighbor[1] < cols and grid[neighbor[0]][neighbor[1]] == 0:\n                tentative = g_score[current] + 1\n                if tentative < g_score.get(neighbor, float('inf')):\n                    came_from[neighbor] = current\n                    g_score[neighbor] = tentative\n                    f = tentative + heuristic(neighbor, goal)\n                    heapq.heappush(open_set, (f, neighbor))\n    return None"),
    ("Create a Bloom filter implementation in Python with configurable false positive rate.", "import math\nimport mmh3\nfrom bitarray import bitarray\n\nclass BloomFilter:\n    def __init__(self, n, p=0.01):\n        self.size = self._m(n, p)\n        self.hash_count = self._k(self.size, n)\n        self.bit_array = bitarray(self.size)\n        self.bit_array.setall(0)\n\n    def _m(self, n, p):\n        return int(-(n * math.log(p)) / (math.log(2) ** 2))\n\n    def _k(self, m, n):\n        return max(1, int((m / n) * math.log(2)))\n\n    def add(self, item):\n        for i in range(self.hash_count):\n            idx = mmh3.hash(item, i) % self.size\n            self.bit_array[idx] = 1\n\n    def __contains__(self, item):\n        return all(\n            self.bit_array[mmh3.hash(item, i) % self.size]\n            for i in range(self.hash_count)\n        )"),
    ("Write a Python script that implements the Raft consensus algorithm leader election simplified.", "import random\nimport time\n\nclass Node:\n    def __init__(self, node_id):\n        self.id = node_id\n        self.state = 'follower'\n        self.term = 0\n        self.voted_for = None\n\n    def start_election(self, nodes):\n        self.state = 'candidate'\n        self.term += 1\n        self.voted_for = self.id\n        votes = 1\n        for node in nodes:\n            if node.id != self.id and node.request_vote(self.term, self.id):\n                votes += 1\n        if votes > len(nodes) // 2:\n            self.state = 'leader'\n            print(f'Node {self.id} became leader for term {self.term}')\n\n    def request_vote(self, term, candidate_id):\n        if term > self.term:\n            self.term = term\n            self.voted_for = candidate_id\n            return True\n        return False"),
    
