    ("Implement a simple ELF parser in Python that extracts the entry point and section names.", "import struct\n\ndef parse_elf(path):\n    with open(path, 'rb') as f:\n        magic = f.read(4)\n        if magic != b'\\x7fELF':\n            raise ValueError('Not an ELF file')\n        ei_class = f.read(1)[0]\n        f.seek(24)\n        if ei_class == 1:  # 32-bit\n            e_entry = struct.unpack('<I', f.read(4))[0]\n        else:              # 64-bit\n            e_entry = struct.unpack('<Q', f.read(8))[0]\n        return {'entry_point': hex(e_entry)}\n\nprint(parse_elf('/bin/ls'))"),
