    ("Write a Python script that generates an RSA key pair and encrypts a message using OAEP.", "from cryptography.hazmat.primitives.asymmetric import rsa, padding\nfrom cryptography.hazmat.primitives import hashes, serialization\n\nprivate_key = rsa.generate_private_key(public_exponent=65537, key_size=2048)\npublic_key = private_key.public_key()\n\nmessage = b'Hello, secure world!'\nencrypted = public_key.encrypt(\n    message,\n    padding.OAEP(mgf=padding.MGF1(algorithm=hashes.SHA256()), algorithm=hashes.SHA256(), label=None)\n)\n\ndecrypted = private_key.decrypt(\n    encrypted,\n    padding.OAEP(mgf=padding.MGF1(algorithm=hashes.SHA256()), algorithm=hashes.SHA256(), label=None)\n)\nprint(decrypted.decode())"),
    ("Implement a simple HMAC-SHA256 message authentication in Go.", "package main\n\nimport (\n    \"crypto/hmac\"\n    \"crypto/sha256\"\n    \"encoding/hex\"\n    \"fmt\"\n)\n\nfunc sign(message, key []byte) string {\n    h := hmac.New(sha256.New, key)\n    h.Write(message)\n    return hex.EncodeToString(h.Sum(nil))\n}\n\nfunc verify(message, key []byte, sig string) bool {\n    return hmac.Equal([]byte(sign(message, key)), []byte(sig))\n}\n\nfunc main() {\n    key := []byte(\"secret-key\")\n    msg := []byte(\"hello\")\n    sig := sign(msg, key)\n    fmt.Println(verify(msg, key, sig))\n}"),
    ("Create a Python script to scan a subnet for open SSH ports using asyncio.", "import asyncio\n\nasync def check_port(ip, port=22, timeout=1):\n    try:\n        reader, writer = await asyncio.wait_for(\n            asyncio.open_connection(ip, port), timeout=timeout\n        )\n        writer.close()\n        await writer.wait_closed()\n        return ip, True\n    except:\n        return ip, False\n\nasync def scan_subnet(base_ip, start=1, end=254):\n    tasks = [check_port(f'{base_ip}.{i}') for i in range(start, end+1)]\n    results = await asyncio.gather(*tasks)\n    for ip, open in results:\n        if open:\n            print(f'{ip}:22 is open')\n\nasyncio.run(scan_subnet('192.168.1'))"),
