    ("Write a Python class that implements the iterator protocol to generate prime numbers lazily.", "class Primes:\n    def __init__(self, max_n):\n        self.max_n = max_n\n        self.n = 2\n    def __iter__(self):\n        return self\n    def __next__(self):\n        while self.n <= self.max_n:\n            is_prime = all(self.n % i != 0 for i in range(2, int(self.n**0.5)+1))\n            val = self.n\n            self.n += 1\n            if is_prime:\n                return val\n        raise StopIteration"),
    ("Create a Python dataclass representing a 3D vector with operator overloading.", "from dataclasses import dataclass\n\n@dataclass(frozen=True)\nclass Vec3:\n    x: float\n    y: float\n    z: float\n\n    def __add__(self, other):\n        return Vec3(self.x + other.x, self.y + other.y, self.z + other.z)\n    def __sub__(self, other):\n        return Vec3(self.x - other.x, self.y - other.y, self.z - other.z)\n    def __mul__(self, scalar):\n        return Vec3(self.x * scalar, self.y * scalar, self.z * scalar)\n    def dot(self, other):\n        return self.x*other.x + self.y*other.y + self.z*other.z"),
    ("Implement a Python profiler that traces function calls using sys.setprofile.", "import sys\n\nclass Profiler:\n    def __init__(self):\n        self.calls = {}\n    def tracer(self, frame, event, arg):\n        if event == 'call':\n            name = frame.f_code.co_name\n            self.calls[name] = self.calls.get(name, 0) + 1\n        return self.tracer\n    def start(self):\n        sys.setprofile(self.tracer)\n    def stop(self):\n        sys.setprofile(None)\n    def report(self):\n        for name, count in sorted(self.calls.items(), key=lambda x: -x[1]):\n            print(f'{name}: {count}')"),
